208	<script>
209	// TODO: オーナーがGoogleフォームを作成後、以下のURLを差し替える
210	const FEEDBACK_URL='';
211	
212	const BOLT={3:{p:0.5,d2:2.675,d3:2.459,As:5.03,dw:5.5,dh:3.4},4:{p:0.7,d2:3.545,d3:3.242,As:8.78,dw:7.0,dh:4.5},5:{p:0.8,d2:4.480,d3:4.134,As:14.2,dw:8.8,dh:5.5},6:{p:1.0,d2:5.350,d3:4.917,As:20.1,dw:10.0,dh:6.6},8:{p:1.25,d2:7.188,d3:6.647,As:36.6,dw:13.0,dh:9.0},10:{p:1.5,d2:9.026,d3:8.376,As:58.0,dw:16.0,dh:11.0},12:{p:1.75,d2:10.863,d3:10.106,As:84.3,dw:18.0,dh:13.5},16:{p:2.0,d2:14.701,d3:13.835,As:157,dw:24.0,dh:17.5},20:{p:2.5,d2:18.376,d3:17.294,As:245,dw:30.0,dh:22.0},22:{p:2.5,d2:20.376,d3:19.294,As:303,dw:34.0,dh:24.0},24:{p:3.0,d2:22.051,d3:20.752,As:353,dw:36.0,dh:26.0},27:{p:3.0,d2:25.051,d3:23.752,As:459,dw:41.0,dh:30.0},30:{p:3.5,d2:27.727,d3:26.211,As:561,dw:46.0,dh:33.0},33:{p:3.5,d2:30.727,d3:29.211,As:694,dw:50.0,dh:36.0},36:{p:4.0,d2:33.402,d3:31.670,As:817,dw:55.0,dh:39.0},39:{p:4.0,d2:36.402,d3:34.670,As:976,dw:60.0,dh:42.0},42:{p:4.5,d2:39.077,d3:37.129,As:1121,dw:65.0,dh:45.0}};
213	const GRADE={'4.6':{Sy:240,Su:400},'4.8':{Sy:340,Su:420},'8.8':{Sy:660,Su:830},'10.9':{Sy:940,Su:1040},'12.9':{Sy:1100,Su:1220},'A2-70':{Sy:450,Su:700},'A4-70':{Sy:450,Su:700},'A4-80':{Sy:600,Su:800},'A2017':{Sy:275,Su:440},'A5052':{Sy:215,Su:265},'A6061':{Sy:275,Su:310},'C3604':{Sy:300,Su:400}};
214	const CL_MAT={spcc:{tau:340,bearing:220,name:'鋼板 SPCC'},steel:{tau:400,bearing:220,name:'鋼 SS400'},s45c:{tau:690,bearing:380,name:'鋼 S45C'},sus304:{tau:520,bearing:185,name:'SUS304'},aluminum:{tau:310,bearing:60,name:'アルミ合金'},cast_iron:{tau:200,bearing:120,name:'鋳鉄 FC200'},brass:{tau:390,bearing:100,name:'真鍮'},resin:{tau:65,bearing:30,name:'エンプラ'}};
215	const MU_MAP={dry:{mt:0.15,mw:0.15,label:'μ=0.15 乾燥'},lube:{mt:0.10,mw:0.10,label:'μ=0.10 潤滑'},grease:{mt:0.08,mw:0.08,label:'μ=0.08 グリス'}};
216	const BAR_COLORS=['bar-red','bar-orange','bar-green'];
217	
218	function ge(id){return document.getElementById(id)}
219	function gv(id){return ge(id).value}
220	
221	function updateChips(){
222	  ge('chip-diam-val').textContent='M'+gv('diam');
223	  const gradeOpt=ge('grade').options[ge('grade').selectedIndex];
224	  ge('chip-grade-val').textContent=gradeOpt.text;
225	  ge('chip-part-val').textContent=CL_MAT[gv('part_mat')].name;
226	  ge('chip-mu-val').textContent=MU_MAP[gv('mu')].label;
227	}
228	
229	function calc(){
230	  const d=+gv('diam');
231	  const grK=gv('grade');
232	  const partMatKey=gv('part_mat');
233	  const {mt,mw}=MU_MAP[gv('mu')];
234	  const sf=1.5;
235	
236	  const b=BOLT[d];
237	  const gr=GRADE[grK];
238	  const clB=CL_MAT[partMatKey];
239	  const dep=1.0;
240	
241	  const Db=(b.dw+b.dh)/2;
242	  const K=b.p/(2*Math.PI*d)+0.577*mt*b.d2/d+mw*Db/(2*d);
243	  const Knd=K*d;
244	  const At=b.p/(2*Math.PI)+0.577*mt*b.d2;
245	  const dAs=Math.sqrt(4*b.As/Math.PI);
246	
247	  const Fy_denom=1+3*Math.pow(3/dAs*At,2);
248	  const Fy=gr.Sy*b.As/Math.sqrt(Fy_denom)/1000;
249	  const T_lim=Knd*Fy;
250	
251	  const nTh=Math.max(1,(dep*d-0.5*b.p)/b.p);
252	  const bArea=(Math.PI/4)*(b.dw*b.dw-b.dh*b.dh);
253	  const bA=CL_MAT[partMatKey].bearing;
254	  const Fbrk=gr.Su*b.As/1000;
255	  const Fstr=clB.tau*Math.PI*d*0.5*b.p*nTh*0.577/1000;
256	  const FbA=bA*bArea/1000;
257	
258	  const failModes=[
259	    {name:'座面陥没 A',F:FbA},
260	    {name:'山せん断',F:Fstr},
261	    {name:'ボルト破断',F:Fbrk}
262	  ].sort((a,b)=>a.F-b.F);
263	
264	  const dominant=failModes[0].name;
265	  const T_fail=failModes[0].F*Knd;
266	  const T_jis=T_lim/sf;           // JIS標準値（ボルト強度基準）
267	  const softMaterials=new Set(['aluminum','cast_iron','brass','resin']);
268	  const isSoft=softMaterials.has(partMatKey);
269	  const T_rec=isSoft?Math.min(T_jis,T_fail/sf):T_jis;
270	  const isMaterialLimit=isSoft&&T_fail/sf<T_jis;
271	
272	  ge('res-torque').textContent=T_rec.toFixed(2);
273	  ge('res-range').textContent=`許容範囲 ${(T_rec*0.9).toFixed(2)} 〜 ${(T_rec*1.1).toFixed(2)} N·m`;
274	
275	  // 警告
276	  const warnEl=ge('warning-banner');
277	  if(isMaterialLimit && dominant.includes('山せん断')){
278	    warnEl.classList.add('show');
279	    ge('warn-title').textContent='⚠️ 相手部材の強度により制限（標準値より低く設定）';
280	    ge('warn-detail').textContent=`JIS B 1083標準値（ボルト強度基準）: ${T_jis.toFixed(2)} N·m ／ 相手部材の山せん断強度を考慮して低減しています。ねじ込み深さを増やすか相手材の強化を推奨します。`;
281	  } else if(isMaterialLimit && dominant.includes('座面')){
282	    warnEl.classList.add('show');
283	    ge('warn-title').textContent='⚠️ 相手部材の強度により制限（標準値より低く設定）';
284	    ge('warn-detail').textContent=`JIS B 1083標準値（ボルト強度基準）: ${T_jis.toFixed(2)} N·m ／ 相手部材の許容面圧を考慮して推奨トルクを低減しています。`;
285	  } else {
286	    warnEl.classList.remove('show');
287	  }
288	
289	  // 破損モードバー
290	  const maxT=failModes[failModes.length-1].F*Knd;
291	  ge('failure-list').innerHTML=failModes.map((fm,i)=>{
292	    const t=(fm.F*Knd).toFixed(2);
293	    const mg=(fm.F*Knd/T_rec).toFixed(2);
294	    const pct=((fm.F*Knd)/maxT*100).toFixed(1);
295	    const isDom=(i===0);
296	    const color=BAR_COLORS[Math.min(i,BAR_COLORS.length-1)];
297	    return `<div class="failure-item">
298	      <div class="fi-header">
299	        <div class="fi-name">${fm.name}${isDom?'<span class="fail-tag-red">制限</span>':''}</div>

300	        <div class="fi-value">${t} N·m / ${mg}×</div>
301	      </div>
302	      <div class="bar-track"><div class="bar-fill ${color}" style="width:${pct}%"></div></div>
303	    </div>`;
304	  }).join('');
305	}
306	
307	function scrollToChips(){
308	  document.querySelector('.chips-grid').scrollIntoView({behavior:'smooth',block:'center'});
309	}
310	
311	function shareResult(){
312	  const t=ge('res-torque').textContent;
313	  const r=ge('res-range').textContent;
314	  const d=gv('diam'),g=gv('grade'),p=CL_MAT[gv('part_mat')].name,m=MU_MAP[gv('mu')].label;
315	  const text=`BoltSense 締め付けトルク計算（JIS B 1083）\nM${d} / ${g} / ${p} / ${m}\n推奨トルク: ${t} N·m\n${r}`;
316	  if(navigator.share){
317	    navigator.share({title:'BoltSense 計算結果',text});
318	  } else if(navigator.clipboard){
319	    navigator.clipboard.writeText(text).then(()=>alert('クリップボードにコピーしました'));
320	  }
321	}
322	
323	function openFeedback(){
324	  if(FEEDBACK_URL){
325	    window.location.href=FEEDBACK_URL;
326	  } else {
327	    alert('フィードバックは takotot20002000@gmail.com までお送りください。');
328	  }
329	}
330	
331	updateChips();
332	calc();
333	</script>
334	</body>
335	</html>
